{"title":"KCP Log Rejection Count","type":"vega","aggs":[],"params":{"spec":"{
  "$schema": "https://vega.github.io/schema/vega-lite/v4.json",
  "data": {
    name: kibana_data_load
    "url": {
      "index": "cls-rejected-*"
      "body": {
        "query": {
          bool: {
              must: [
                %dashboard_context-must_clause%
                { match: { "index_prefix": "logs-json-kyma" } }
              ]
              filter: [
                %dashboard_context-filter_clause%
                {
                  range: {
                    @timestamp: {
                      gte: {
                        %timefilter%: min
                      }
                      lte: {
                        %timefilter%: max
                      }
                    }
                  }
                }
              ]
              must_not: [
                %dashboard_context-must_not_clause%
              ]
            }
        }
        "size": 0
      }
    }
  },
  "transform": [
    {
      "calculate": "datum.hits.total > 0 ? datum.hits.total : 0",
      "as": "count"
    }
    {
      "calculate": "'Total Rejections'",
      "as": "title"
    }
  ],
  "layer": [
    {
      "encoding": {
        "text": {
          "field": "count"
        }
        "color": {
          "condition": {"test": "datum.hits.total < 1", "value": "#54b399"}
          "value": "#e7664c"
        }
      },
      "mark": {
        "type": "text",
        "fontSize": 75,
        "fontWeight": "bold"
        "yOffset": 33
        "font": "Inter UI, -apple-system, BlinkMacSystemFont, Segoe UI, Helvetica, Arial, sans-serif, Apple Color Emoji, Segoe UI Emoji, Segoe UI Symbol"
      },
    },
    {
      "encoding": {
        "text": {
          "field": "title"
        }
        "color": {
          "value": "#9D9D9D"
        }
      },
      "mark": {
        "type": "text",
        "fontSize": 40,
        "yOffset": -33
        "font": "Inter UI, -apple-system, BlinkMacSystemFont, Segoe UI, Helvetica, Arial, sans-serif, Apple Color Emoji, Segoe UI Emoji, Segoe UI Symbol"
      },
    }
  ]
  "config": {
    "view": {
      "stroke": "transparent"
    }
  }
}"}}

{"title": "KCP Log Rejections by Application", "type": "vega", "aggs": [], "params": {"spec": "{
  $schema: https://vega.github.io/schema/vega/v5.json
  data: [
    {
      name: rejectionsTable
      url: {
        index: cls-rejected-*
        body: {
          size: 0
          query: {
            bool: {
              filter: [
                {match: {index_prefix: "logs-json-kyma"}}
                {range: {"@timestamp": {gte: "now-24h" lte: "now"}}}
              ]
            }
          }
          aggs: {
            by_app: {
              terms: {
                size: 50
                script: {
                  lang: painless
                  source: "if (!params._source.containsKey('payload')) { return 'unknown'; } String p = params._source.payload; int i = p.indexOf('app_name'); if (i < 0) { return 'unknown'; } int s = p.indexOf(':', i) + 2; int e = p.indexOf(',', s) - 1; if (s < 2 || e < 0) { return 'unknown'; } return p.substring(s, e);"
                }
              }
            }
          }
        }
      }
      format: {property: "aggregations.by_app.buckets"}
      transform: [
        {type: "formula" as: "app" expr: "datum.key"}
        {type: "formula" as: "count" expr: "datum.doc_count"}
      ]
    }
  ]
  scales: [
    {name: "xscale" type: "linear" domain: {data: "rejectionsTable" field: "count"} range: "width" nice: true}
    {name: "yscale" type: "band" domain: {data: "rejectionsTable" field: "app" sort: {field: "count" order: "descending"}} range: "height" padding: 0.2}
  ]
  axes: [
    {orient: "left" scale: "yscale"}
    {orient: "bottom" scale: "xscale" format: "d"}
  ]
  marks: [
    {
      type: "rect"
      from: {data: "rejectionsTable"}
      encode: {
        enter: {
          y: {scale: "yscale" field: "app"}
          height: {scale: "yscale" band: 1}
          x: {scale: "xscale" field: "count"}
          x2: {scale: "xscale" value: 0}
          fill: {value: "#e7664c"}
          tooltip: {signal: "{'Application': datum.app, 'Rejections': datum.count}"}
        }
      }
    }
    {
      type: "text"
      from: {data: "rejectionsTable"}
      encode: {
        enter: {
          y: {scale: "yscale" field: "app" offset: {scale: "yscale" band: 0.5}}
          x: {scale: "xscale" field: "count" offset: 4}
          baseline: {value: "middle"}
          text: {field: "count"}
          fontSize: {value: 11}
          fill: {value: "#343741"}
        }
      }
    }
  ]
  config: {kibana: {hideWarnings: "true"}}
}"}}

